import{_ as i,o as t,c as e,a3 as a}from"./chunks/framework.aYYe0dfI.js";const c=JSON.parse('{"title":"clore::support::striputf8bom","description":"The function checks whether the input std::string_view text begins with the UTF‑8 byte‑order mark (BOM) stored in the constant kUtf8Bom. It first verifies that text.size() is at least std::size(kUtf8Bom) (three bytes) and then compares each of the first three bytes using static_cast<unsigned char> to avoid sign extension. If all three match, it returns the substring starting after the BOM; otherwise it returns the original text unchanged. No additional helpers or external dependencies are required; the only dependency is the constant kUtf8Bom defined in the same anonymous namespace.","frontmatter":{"title":"clore::support::striputf8bom","description":"The function checks whether the input std::string_view text begins with the UTF‑8 byte‑order mark (BOM) stored in the constant kUtf8Bom. It first verifies that text.size() is at least std::size(kUtf8Bom) (three bytes) and then compares each of the first three bytes using static_cast<unsigned char> to avoid sign extension. If all three match, it returns the substring starting after the BOM; otherwise it returns the original text unchanged. No additional helpers or external dependencies are required; the only dependency is the constant kUtf8Bom defined in the same anonymous namespace.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/support/functions/strip-utf8-bom.md","filePath":"en/clore/modules/support/functions/strip-utf8-bom.md"}'),n={name:"clore/modules/support/functions/strip-utf8-bom.md"};function h(r,s,l,p,o,k){return t(),e("div",null,[...s[0]||(s[0]=[a("",16)])])}const g=i(n,[["render",h]]);export{c as __pageData,g as default};
